    function flipBackSide(modelPosition, w, h, q, cb) {
      //!sk changes for 360 back & Side's Download
      //window.isActivity = true;
      if (window.getAnimationStatus()) setTimeout(() => window.stopAnimate(false), 0); //!sk
      const bbox = window.getloadedObject()[0].bbox;
      let center = new Vector3$1();
      bbox.getCenter(center);
      let size = new Vector3$1();
      bbox.getSize(size);
      controls.target.set(center.x, center.y, center.z);
      // camera.position.set(center.x, center.y / 2, center.z); // front
      //camera.position.set(center.x, center.y, center.z / 2);
      if (modelPosition === 'btnleft' || modelPosition === 'left') {
        camera.position.set(center.x / 2, center.y / 2, center.z); // left
      } else if (modelPosition === 'btnright' || modelPosition === 'right') {
        camera.position.set(center.x * 2, center.y, center.z); //right 
      } else if (modelPosition === 'btnback' || modelPosition === 'back') {
        if (center.z < 0) {
          camera.position.set(center.x, center.y, center.z * 2);
        } else {
          camera.position.set(center.x, center.y, center.z / 2);
        }
      } else if (modelPosition === 'btnfront' || modelPosition === 'front') {
        camera.position.set(center.x, center.y / 2, center.z); // front
      } else {
        camera.position.set(center.x, center.y, center.z); //default
      }
      camera.rotation.y = Math.PI;
      camera.lookAt(center);
      controls.update();
      window.getDollyOut(25);
      setTimeout(function () {
        const base64Image = that.container.querySelector('canvas').toDataURL('image/png');
        console.log('base64Image', base64Image);
        // const containerCanvas = that.container.querySelector('canvas');
        const canvas = document.createElement('canvas');
        canvas.width = that.container.querySelector('canvas').width;
        canvas.height = that.container.querySelector('canvas').height;
        // const ctx = canvas.getContext('2d');

        const img = new Image();
        img.src = base64Image;
        img.onload = function () {
          const originalWidth = img.width;
          const originalHeight = img.height;
          let cropLeft = originalWidth * 1;
          let cropRight = originalWidth * 1;
          if (modelPosition === 'left' || modelPosition === 'btnleft' || modelPosition === 'right' || modelPosition === 'btnright') {
            cropLeft = originalWidth * 1;
            cropRight = originalWidth * 1;
          }
          const newWidth = originalWidth - cropLeft - cropRight;
          const aspectRatio = originalHeight / originalWidth;
          const newHeight = newWidth * aspectRatio;
          const targetWidth = w && w * (that.downloadImageQuality || 1) || canvas.width;
          const targetHeight = h && h * (that.downloadImageQuality || 1) || canvas.height;
          let scaleWidth, scaleHeight;
          if (newWidth / newHeight > targetWidth / targetHeight) {
            scaleWidth = targetWidth;
            scaleHeight = targetWidth * (newHeight / newWidth);
          } else {
            scaleHeight = targetHeight;
            scaleWidth = targetHeight * (newWidth / newHeight);
          }
          canvas.width = scaleWidth;
          canvas.height = scaleHeight;
          const ctx = canvas.getContext('2d');
          ctx.drawImage(img, cropLeft, 0, newWidth, originalHeight, 0, 0, scaleWidth, scaleHeight);
          const cropImage = canvas.toDataURL('image/png', 1.0);
          cb(cropImage);
        };
      }, 100);
    }

