    function render() {
      TWEEN.update();
      controls.update();
      renderer.clear();
      // renderer.render( pickingScene, camera );
      if (camera) {
        renderer.render(scene, camera);
      }
    }
    function loadObject(url, index, dLayer1, dLayer2, dLayer3, shadow_path, texture, twidth, theight, callback, loadRefer, orderNo, isButton, product_name) {
    		if (window.getAnimationStatus()) setTimeout(() => window.stopAnimate(false), 0); //!sk
let threeD = new threeDObject({
    		isiOSF: isiOSF,
    		url: url,
    		shadow_path: shadow_path,
    		texture: texture,
    		defaultTexture: that.defaultTexture,
    		isSkinColor: that.isSkinColor,
    		isShoesColor: that.isShoesColor,
    		isButton: isButton,
    		loadRefer: loadRefer,
    		orderNo: orderNo,
    		// btnColor: btnColor,
    		dpiCache: that.dpiCache,
    		twidth: twidth,
    		theight: theight,
    		dracoPath: that.dracoPath,
    		vertexShader: that.vertexShader,
    		//fragmentShader: that.fragmentShader,
    		webpSupport: isWebpSupport,
    		product_name,
    		debug: that.debug,
    		callback: function (mesh, isThreeD, isOrderd, Ref, orNo) {
    			// scene.add(scenes);
    			//console.log(mesh);

    			// remove previous objects
    			//clearScene();

    			if (!mesh) {
    				if (callback && typeof callback === 'function') {
    					callback(false);
    				}
    			}
    			var groupsconfig = Object.keys(mesh);
      //    groupsconfig.dispose();
    			// console.log(groupsconfig);

    			if (currentRef !== null) {
    				if (currentRef !== Ref) {
    					return;
    				}
    			}
    			if (Object.keys(loadedObjects).indexOf(index) > -1) {
    				createLoadObjectStruct(index);
    			}

    			// if(!orderNo)
    			// finalposition = false; //! comment

    			// if(Object.keys(loadedObjects).indexOf(getThreeDImageName(this.url)) === -1){ return; }

    			if (!isThreeD && orNo !== undefined && orNo !== '') {
    				ordering[orNo].meshcount += threeD.getAllMesh().length;
    				// console.log(ordering);
    			} else if (!isOrderd) {
    				// console.log(mesh);
    				for (var groupname in mesh) {
    					if (Object.prototype.hasOwnProperty.call(mesh, groupname)) {
    						for (var m in mesh[groupname]) {
    							if (Object.prototype.hasOwnProperty.call(mesh[groupname], m)) {
    								// groupsconfig[parseInt(mesh[groupname][m].name.match(/\d+/g)[0])] = parseInt(mesh[groupname][m].name.match(/\d+/g)[0]);
    								// groupsconfig.push(mesh[groupname][m].name);

    								mesh[groupname][m].position.z = mesh[groupname][m].position.z + meshzPositon;
    								// meshzPositon += 0.0001; //Added Tanmay Chnages As Per Requirement 20-01-2024
    								// meshzPositon += 0.001;
    								meshzPositon = 0;
    								loadedObjects[index].bbox.union(mesh[groupname][m]['bbox']);
    								mesh[groupname][m].castShadow = false;
    								scene.add(mesh[groupname][m]);

    								// pickingScene.add(threeD.getPickingMesh(groupname,m,(parseInt(m) + 1)));
    								// mgConfig[parseInt(m) + 1] = groupname;
    							}
    						}
    					}
    				}
    			} else {
    				var meshes = threeD.getAllMesh();
    				for (m in meshes) {
    					if (Object.prototype.hasOwnProperty.call(meshes, m)) {
    						// groupsconfig[parseInt(mesh[m].name.match(/\d+/g)[0])] = parseInt(mesh[m].name.match(/\d+/g)[0]);
    						// groupsconfig.push(meshes[m].name);

    						meshes[m].position.z = meshes[m].position.z + meshzPositon;
    						// meshzPositon += 0.0001; //Added Tanmay Chnages As Per Requirement 20-01-2024
    						// meshzPositon += 0.001;
    						meshzPositon = 0;
    						loadedObjects[index].bbox.union(meshes[m]['bbox']);
    						meshes[m].castShadow = false;
    						scene.add(meshes[m]);
    					}
    				}
    			}
    			threeD['isThreeD'] = isThreeD;
    			// isThreeDObject = isThreeD;
    			loadedObjects[index].isThreeDObject = isThreeD;

    			// controls.maxPanningX = bbox.maxX + ((bbox.maxX/100) * 10);
    			// controls.minPanningX = bbox.minX + ((bbox.minX/100) * 10);

    			if (!loadedObjects[index][dLayer1]) {
    				loadedObjects[index][dLayer1] = {
    					dLayer1: {},
    					dLayer2: {},
    					dLayer3: {}
    				};
    			}
    			if (dLayer3 !== undefined) {
    				if (Object.prototype.hasOwnProperty.call(loadedObjects[index][dLayer1].dLayer3, dLayer3)) {
    					if (Object.prototype.hasOwnProperty.call(loadedObjects[index][dLayer1].dLayer3[dLayer3], dLayer2)) {
    						loadedObjects[index][dLayer1].dLayer3[dLayer3][dLayer2] = threeD;
    					} else {
    						loadedObjects[index][dLayer1].dLayer3[dLayer3][dLayer2] = threeD;
    					}
    				} else {
    					loadedObjects[index][dLayer1].dLayer3[dLayer3] = {};
    					loadedObjects[index][dLayer1].dLayer3[dLayer3][dLayer2] = {};
    					loadedObjects[index][dLayer1].dLayer3[dLayer3][dLayer2] = threeD;
    				}
    			} else if (dLayer2 !== undefined) {
    				loadedObjects[index][dLayer1].dLayer2[dLayer2] = threeD;
    			} else if (dLayer1 !== undefined) {
    				loadedObjects[index][dLayer1].dLayer1 = threeD;
    			}

    			//if(that.debug){console.log(JSON.stringify(scene.toJSON()));}

    			// console.log(scene);
    			setTimeout(() => window.stopAnimate(true), 2200); //!sk

    			if (callback && typeof callback === 'function') {
    				callback(true, groupsconfig, threeD);
    			}
    		}
    	});

    	// that.ThreeDObjects.push(threeD);

    	// loadedObjects[getThreeDImageName(url)] = threeD;
    }

