    function setAspectRatio() {
      cameraAspect = that.container.clientWidth / that.container.clientHeight;
      finalposition = false;
      if (camera.type === 'PerspectiveCamera') {
        camera.aspect = cameraAspect;
        camera.updateProjectionMatrix();
      } else {
        camera.left = that.container.clientWidth / -2;
        camera.right = that.container.clientWidth / 2;
        camera.top = that.container.clientHeight / 2;
        camera.bottom = that.container.clientHeight / -2;
        camera.updateProjectionMatrix();
      }
      renderer.setSize(that.container.clientWidth, that.container.clientHeight);
      pickingTexture.setSize(that.container.clientWidth, that.container.clientHeight);
    }
    that.container.querySelector('canvas').addEventListener('click', onMouseClick, false);
    function getCanvasRelativePosition(x, y, canvas) {
      const rect = canvas.getBoundingClientRect();
      return {
        x: (x - rect.left) * canvas.width / rect.width,
        y: (y - rect.top) * canvas.height / rect.height
      };
    }

