    let clearActivity = null;
    this.container.querySelector('canvas').addEventListener('dblclick', function (event) {
      if (!controls.enabled || /^((?!chrome|android).)*safari/i.test(navigator.userAgent) && camera.isOrthographicCamera) {
        return;
      }
      setTimeout(() => {
        window.isActivity = true;
        if (window.getAnimationStatus()) {
          window.stopAnimate(false);
        }
        if (clearActivity) {
          clearTimeout(clearActivity);
          clearActivity = setTimeout(() => window.isActivity = false, 3000);
        } else {
          clearActivity = setTimeout(() => window.isActivity = false, 3000);
        }
      }, 0); //!sk
      var x = event.clientX;
      var y = event.clientY;
      cursorZoom(x, y);
    });
    var touchLenght = 0;
    this.container.addEventListener('touchstart', function (event) {
      if (!controls.enabled) {
        return;
      }
      touchLenght = event.touches.length;
    });
    var timeout;
    var lastTap = 0;
    this.container.addEventListener('touchend', function (event) {
      if (!controls.enabled || /^((?!chrome|android).)*safari/i.test(navigator.userAgent) && camera.isOrthographicCamera) {
        return;
      }
      if (touchLenght < 2) {
        var currentTime = new Date().getTime();
        var tapLength = currentTime - lastTap;
        clearTimeout(timeout);
        if (tapLength < 500 && tapLength > 0) {
          var target = event.changedTouches[0];
          var x = target.clientX;
          var y = target.clientY;
          cursorZoom(x, y);
          // event.preventDefault();
        }
        lastTap = currentTime;
        touchLenght = 0;
      } else {
        touchLenght = 0;
      }
    });
    function cursorZoom(x, y) {
      var canvas = that.container.querySelector('canvas');
      var pos = getCanvasRelativePosition(x, y, canvas);
      mouse.x = pos.x / canvas.width * 2 - 1;
      mouse.y = pos.y / canvas.height * -2 + 1; // note we flip Y

      // Raycaster For Selection of Object
      // var raycaster = new Raycaster();
      raycaster.setFromCamera(mouse.clone(), camera);
      // // console.log(raycaster);
      var intersects = raycaster.intersectObjects(scene.children, true);
      var FirstObject = 0;
      for (var i = 0; i < intersects.length; i++) {
        if (intersects[i].object.type.toLowerCase() !== 'mesh') {
          FirstObject++;
          continue;
        }
        if (i === FirstObject) {
          var intersection = intersects[i];
          //var obj = intersection.object.parent;

          if (that.CursorZoom) {
            if (!IsCursorZoom) {
              cameraLook(controls.target, {
                x: intersection.point.x,
                y: intersection.point.y,
                z: intersection.point.z
              }, function () {
                zoomInAnimation({
                  x: 0
                }, {
                  x: 20
                });
                IsCursorZoom = true;
              });
            } else {
              if (that.onZoomOut && typeof that.onZoomOut === 'function') {
                that.onZoomOut();
              }
              // resetModel();
            }
          }

          // if (that.OnObjectClick) {
          //   that.OnObjectClick(obj.DetailId, obj.FeatureId);
          // }
        }
      }
    }
    function zoomInAnimation(start, end, callback) {
      var tween = new TWEEN.Tween(start) // Create a new tween that modifies 'coords'.
        .to(end, 500).easing(TWEEN.Easing.Linear.None).onUpdate(function () {
          controls.zoomIn();
        }).onComplete(function () {
          if (callback && typeof callback === 'function') {
            callback();
          }
        });
      tween.start();
    }
    function resetModel(bbox, isThreeDObject) {
      //if (window.getAnimationStatus()) setTimeout(() => window.stopAnimate(false), 0); //!sk
      IsCursorZoom = false;
      resetAnimation(bbox, isThreeDObject);
      controls.update();
      //setTimeout(() => window.isActivity = false, 3000);//!sk
    }

